DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM candidatos WHERE slug = 'jhc' AND publicavel = true) THEN
    RAISE EXCEPTION 'jhc nao encontrado ou nao publicavel';
  END IF;
END $$;

