WITH target AS (
  SELECT c.id AS candidato_id, seed.*, (
    SELECT hp.id FROM historico_politico hp
    WHERE hp.candidato_id = c.id AND hp.tipo_evento = 'mandato' AND UPPER(COALESCE(hp.estado,'')) = 'AL'
      AND (hp.cargo ILIKE '%Prefeito%' OR hp.cargo_canonico = 'Prefeito')
      AND COALESCE(hp.periodo_inicio,9999) <= EXTRACT(YEAR FROM seed.data_norma::date)::int
      AND COALESCE(hp.periodo_fim,9999) >= EXTRACT(YEAR FROM seed.data_norma::date)::int
    ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id LIMIT 1
  ) AS historico_politico_id
  FROM candidatos c CROSS JOIN _seed_jhc_maceio_camara_lme seed
  WHERE c.slug = 'jhc' AND c.publicavel = true
)
INSERT INTO legislacao_mandato_executivo (candidato_id,historico_politico_id,tipo_relacao,esfera,uf_norma,municipio_norma,tipo_norma,numero,ano,data_norma,ementa,signatario,autoridade_papel,fonte_primaria_url,fonte_primaria_titulo,fonte_tramitacao_url,identificador_fonte,metadata)
SELECT candidato_id,historico_politico_id,tipo_relacao,esfera,uf_norma,municipio_norma,tipo_norma,numero,ano,data_norma::date,ementa,signatario,autoridade_papel,fonte_primaria_url,fonte_primaria_titulo,fonte_tramitacao_url,identificador_fonte,metadata
FROM target
WHERE historico_politico_id IS NOT NULL
  AND NOT EXISTS (SELECT 1 FROM legislacao_mandato_executivo lme WHERE lme.candidato_id = target.candidato_id AND lme.identificador_fonte = target.identificador_fonte);

DO $$
DECLARE jhc_id uuid; total_count int; delta_count int;
BEGIN
  SELECT id INTO jhc_id FROM candidatos WHERE slug = 'jhc' AND publicavel = true;
  SELECT count(*) INTO total_count FROM legislacao_mandato_executivo WHERE candidato_id = jhc_id;
  SELECT count(*) INTO delta_count FROM legislacao_mandato_executivo WHERE candidato_id = jhc_id AND metadata ->> 'coverage_id' = 'jhc-maceio-camara-leis-assinadas-jhc-2021-2026-20260704';
  IF total_count <> 32 THEN RAISE EXCEPTION 'jhc LME total esperado 32, encontrado %', total_count; END IF;
  IF delta_count <> 23 THEN RAISE EXCEPTION 'jhc LME delta esperado 23, encontrado %', delta_count; END IF;
END $$;
